code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Button, Badge, icon } from 'decantr/components';

code.example:
function CardGridProduct({ items }) {
  const { div, img, span, p } = tags;

  const products = items || [
    { name: 'Wireless Headphones', price: '$79.99', rating: 4.5, reviews: 128, image: '/images/headphones.jpg' },
    { name: 'Mechanical Keyboard', price: '$149.99', rating: 4.8, reviews: 256, image: '/images/keyboard.jpg' },
    { name: 'USB-C Hub', price: '$49.99', rating: 4.2, reviews: 89, image: '/images/hub.jpg' },
    { name: 'Webcam HD', price: '$69.99', rating: 4.6, reviews: 312, image: '/images/webcam.jpg' },
  ];

  return div({ class: css('_grid _gc1 _sm:gc2 _lg:gc3 _xl:gc4 _gap4') },
    ...products.map(product =>
      Card({ class: css('_flex _col _overflow[hidden]') },
        div({ class: css('_aspect[4/3] _overflow[hidden]') },
          img({ src: product.image, alt: product.name, class: css('_wfull _hfull _object[cover]') })
        ),
        div({ class: css('_flex _col _gap2 _p4') },
          p({ class: css('_textsm _fontmedium') }, product.name),
          p({ class: css('_heading4') }, product.price),
          div({ class: css('_flex _aic _gap1') },
            ...Array.from({ length: 5 }, (_, i) =>
              icon(i < Math.floor(product.rating) ? 'star' : 'star', {
                size: '0.75rem',
                class: css(i < Math.floor(product.rating) ? '_fgprimary' : '_fgmuted')
              })
            ),
            Badge({ variant: 'secondary', size: 'sm' }, `${product.reviews}`)
          )
        ),
        div({ class: css('_p4 _pt0') },
          Button({ variant: 'primary', size: 'sm', class: css('_wfull') }, icon('shopping-cart', { size: '1em' }), ' Add to Cart')
        )
      )
    )
  );
}

