function CardGridContent({ items }) {
  const { div, img, h3, p, span, time } = tags;

  const posts = items || [
    { title: 'Getting Started with Decantr', excerpt: 'Learn how to build your first app with the AI-native framework.', category: 'Tutorial', author: 'Jane Doe', date: '2025-03-15', image: '/images/post1.jpg' },
    { title: 'Advanced Signal Patterns', excerpt: 'Deep dive into reactive signal composition and derived state.', category: 'Guide', author: 'John Smith', date: '2025-03-12', image: '/images/post2.jpg' },
    { title: 'Registry-Driven UI', excerpt: 'How the content registry powers intelligent code generation.', category: 'Architecture', author: 'Alex Chen', date: '2025-03-10', image: '/images/post3.jpg' },
  ];

  return div({ class: css('_grid _gc1 _md:gc2 _lg:gc3 _gap6') },
    ...posts.map(post =>
      Card({ class: css('_flex _col _overflow[hidden]') },
        div({ class: css('_aspect[16/9] _overflow[hidden]') },
          img({ src: post.image, alt: post.title, class: css('_wfull _hfull _object[cover]') })
        ),
        div({ class: css('_flex _col _gap3 _p4') },
          Badge({ variant: 'outline', size: 'sm' }, post.category),
          h3({ class: css('_heading4') }, post.title),
          p({ class: css('_bodysm _fgmuted _line-clamp[2]') }, post.excerpt),
          div({ class: css('_flex _aic _gap2 _textsm _fgmuted') },
            span({}, post.author),
            span({}, '·'),
            time({}, post.date)
          )
        )
      )
    )
  );
}

