function CardGridCollection({ items }) {
  const { div, img, h3 } = tags;

  const collections = items || [
    { name: 'Electronics', count: 234, image: '/images/electronics.jpg' },
    { name: 'Clothing', count: 567, image: '/images/clothing.jpg' },
    { name: 'Home & Garden', count: 189, image: '/images/home.jpg' },
    { name: 'Sports', count: 312, image: '/images/sports.jpg' },
    { name: 'Books', count: 445, image: '/images/books.jpg' },
    { name: 'Toys', count: 178, image: '/images/toys.jpg' },
  ];

  return div({ class: css('_grid _gc2 _lg:gc3 _gap4') },
    ...collections.map(col =>
      Card({ class: css('_relative _aspect[3/2] _overflow[hidden] _cursor[pointer] _group') },
        img({ src: col.image, alt: col.name, class: css('_absolute _inset0 _wfull _hfull _object[cover] _transition _group-hover:scale[1.05]') }),
        div({ class: css('_absolute _inset0 _bg[linear-gradient(transparent_40%,rgba(0,0,0,0.7))]') }),
        div({ class: css('_absolute _bottom0 _left0 _right0 _p4 _flex _jcsb _aic') },
          h3({ class: css('_heading3 _fgfg') }, col.name),
          Badge({ variant: 'secondary' }, `${col.count} items`)
        )
      )
    )
  );
}

