function CardGridIcon({ items }) {
  const { div, h4, p } = tags;

  const features = items || [
    { title: 'Fast Build', description: 'Lightning-fast compilation and HMR', ic: 'zap' },
    { title: 'Type Safe', description: 'Full TypeScript support out of the box', ic: 'shield' },
    { title: 'Responsive', description: 'Mobile-first responsive design system', ic: 'smartphone' },
    { title: 'Accessible', description: 'WCAG 2.1 AA compliant components', ic: 'eye' },
    { title: 'Themeable', description: 'Dark mode and custom theme support', ic: 'palette' },
    { title: 'Extensible', description: 'Plugin architecture for custom needs', ic: 'puzzle' },
    { title: 'Tested', description: 'Comprehensive test coverage built in', ic: 'check-circle' },
    { title: 'Documented', description: 'Detailed docs with live examples', ic: 'book-open' },
  ];

  return div({ class: css('_grid _gc2 _md:gc3 _lg:gc4 _gap3') },
    ...features.map(feature =>
      Card({ class: css('_flex _col _aic _tc _gap2 _p4') },
        div({ class: css('_w10 _h10 _flex _center _rfull _bgmuted/10') },
          icon(feature.ic, { size: '1.25rem', class: css('_fgprimary') })
        ),
        h4({ class: css('_textsm _fontmedium') }, feature.title),
        p({ class: css('_textxs _fgmuted') }, feature.description)
      )
    )
  );
}

